CREATE EXTERNAL TABLE dbo.salesIndiaPARQUET
WITH(
        LOCATION = 'Processed/INDIAparquet/',
        DATA_SOURCE = [synapse-container_sarmastorage_dfs_core_windows_net],
	    FILE_FORMAT = SynapseParquetFormat
) AS 
SELECT * FROM dbo.sales where country = 'India';

SELECT * FROM dbo.salesIndiaparquet;

CREATE EXTERNAL FILE FORMAT SynapseParquetFormat
WITH (
    FORMAT_TYPE = PARQUET
);
